# PER_CHAT_PARALLEL_V1 — per-chat-id worker pool. Each chat_id gets a dedicated
# thread so a slow Claude call in one chat does not block others. Within a
# chat, messages still process sequentially (preserves ordering).
_chat_queues = {}
_chat_queues_lock = threading.Lock()

def _chat_worker(chat_id, q):
    while True:
        try:
            item = q.get()
            if item is None:
                continue
            line, idx = item
            try:
                process_line(line, idx)
            except Exception as e:
                try:
                    log(ERR_LOG, f"worker[{chat_id[:18]}] L{idx}: {e}")
